VENUES = ['CHI', 'CSCW', 'Ubicomp', 'DIS', 'PervasiveHealth', 'WWW', 'IUI', 'OzCHI', 'TEI', 'AH']
YEAR_MIN = 2000
YEAR_MAX = 2030

# Helper functions

def extract_year_from_head(text):
    head = text[:6000]
    lines = head.split('\n')[:80]
    # First pass: lines with venue
    for line in lines:
        low = line.lower()
        if any(v.lower() in low for v in VENUES):
            # Try 4-digit year
            y = None
            num = ''
            for ch in line:
                if ch.isdigit():
                    num += ch
                    if len(num) >= 4:
                        try:
                            val = int(num[-4:])
                            if YEAR_MIN <= val <= YEAR_MAX:
                                y = val
                                break
                        except Exception:
                            pass
                else:
                    num = ''
            if y is not None:
                return y
            # Try two-digit year after apostrophe
            apos_positions = []
            for i, ch in enumerate(line):
                if ch == "'" or ch == '’':
                    apos_positions.append(i)
            for pos in apos_positions:
                if pos + 3 <= len(line):
                    sub = line[pos+1:pos+3]
                    if sub.isdigit():
                        yy = int(sub)
                        y = 2000 + yy if yy <= 30 else 1900 + yy
                        if YEAR_MIN <= y <= YEAR_MAX:
                            return y
    # Second pass: copyright
    for line in lines:
        low = line.lower()
        if 'copyright' in low or '©' in line or '(c)' in low:
            # find 4-digit year in line
            num = ''
            for ch in line:
                if ch.isdigit():
                    num += ch
                    if len(num) >= 4:
                        try:
                            val = int(num[-4:])
                            if YEAR_MIN <= val <= YEAR_MAX:
                                return val
                        except Exception:
                            pass
                else:
                    num = ''
    # Fallback: first 4-digit year in head
    num = ''
    for ch in head:
        if ch.isdigit():
            num += ch
            if len(num) >= 4:
                try:
                    val = int(num[-4:])
                    if YEAR_MIN <= val <= YEAR_MAX:
                        return val
                except Exception:
                    pass
        else:
            num = ''
    return None


def has_empirical(text, filename):
    tl = text.lower()
    fl = filename.lower()
    if 'empirical' in tl or 'empirical' in fl:
        return True
    # Check explicit contributions line
    head = text[:8000]
    lines = head.split('\n')[:150]
    for line in lines:
        low = line.lower()
        if 'contribution' in low:
            if 'empirical' in low:
                return True
    return False

