        if year_found is not None:
            break
    if year_found is None:
        # Try copyright lines
        for line in lines:
            low = line.lower()
            if ('copyright' in low) or ('©' in line) or ('(c)' in low):
                for y in years_to_check:
                    ys = str(y)
                    if ys in line:
                        year_found = y
                        break
            if year_found is not None:
                break
    if year_found is None:
        # Fallback: search any line for a year
        for line in lines:
            for y in years_to_check:
                if str(y) in line:
                    year_found = y
                    break
            if year_found is not None:
                break
    has_emp = ('empirical' in text.lower())
    if has_emp:
        count_empirical += 1
